              "type": "string",
              "description": "The email adress which sent the email"
            }
          },
          "additionalProperties": false
        },
        "customer": {
          "type": "object",
          "required": [
            "name",
            "organization",
            "department",
            "address",
            "phone",
            "email"
          ],
          "properties": {
            "name": {
              "type": "string"
            },
            "organization": {
