                }
              },
              "additionalProperties": false
            },
            "phone": {
              "type": "string"
            },
            "email": {
              "type": "string",
              "format": "email"
            }
          },
          "additionalProperties": false
        },
        "products": {
          "type": "array",
          "items": {
            "type": "object",
            "required": [
              "lineNumber",
