const emailData = new Map() 

if ($input.first().binary) {
  const attachmentsBinary = [];
  const attachments = Object.values($input.first().binary);
  for (const attachment of attachments) {
    attachmentsBinary.push({json:attachment});
  }
  emailData['binary'] = attachmentsBinary;
}else {
  emailData['attachementData'] = 'N/A'
}

emailData['email_content'] = $input.first().json.text;
emailData['date'] = $input.first().json.date;
emailData['sender_name'] = $input.first().json.from.value[0].name;
emailData['email_sender'] = $input.first().json.from.value[0].address;
emailData['email_subject'] = $input.first().json.subject;

return emailData;

let attachementData = '';
for(const pdf of $input.first().json.pdf) {
  attachementData += `--------------------- DATA FROM PDF FILE ${pdf.fileName} --------------------------- \n`
  attachementData += pdf.text
  attachementData += `-------------------------------------------------------------------------- \n\n`
}

for(const xlsx of $input.first().json.xlsx){
  attachementData += `--------------------- DATA FROM XLSX FILE --------------------------- \n`
  attachementData += JSON.stringify(xlsx)
  attachementData += `-------------------------------------------------------------------------- \n\n`
}


return {
  json:{
    attachementData
  }
};

const { data } = $input.first().json;

console.log(data);

const vendorNames = new Set();
const lotNumbers = new Set();
const vendorIds = new Set();
const purchaseOrderCode = new Set();

for (const { vendor, lotNumber, orderCode } of data.products ?? []) {
  if (vendor?.name && vendor.name !== "N/A") {
    vendorNames.add(vendor.name);
  }

  if (lotNumber && lotNumber !== "N/A") {
    lotNumbers.add(lotNumber);
  }

  if (vendor?.id && vendor.id !== 0) {
    vendorIds.add(vendor.id);
  }

  if (orderCode && orderCode !== 'N/A') {
    purchaseOrderCode.add(orderCode);
  }
}

return {
  customerName: data.customer?.organization,
  customerPhoneNumber: data.customer?.phone,
  customerEmail: data.customer?.email,
  issue: data.issues,
  ticketId: data.creationResult?.ticketId,
  ticketCreatedAt: data.creationResult?.createdAt,
  followUp: "none",
  vendorName: [...vendorNames].join(", "),
  lotNumbers: [...lotNumbers].join(", "),
  vendorIds: [...vendorIds].join(", "),
  orderCodes: [...purchaseOrderCode].join(', ')
};

function safeParseJson(rawJson) {
  // Try direct parse first
  try {
    return JSON.parse(rawJson);
  } catch (e1) {
    // Try stripping markdown code fences
    const cleaned = rawJson
      .replace(/^```(?:json)?\s*\n?/i, "")
      .replace(/\n?```\s*$/i, "")
      .trim();

    try {
      return JSON.parse(cleaned);
    } catch (e2) {
      // Try extracting JSON object from text
      const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        try {
          return JSON.parse(jsonMatch[0]);
        } catch (e3) {
          throw new Error(
            `Failed to parse AI output as JSON. Raw (first 500 chars): ${rawJson.substring(0, 500)}`,
          );
        }
      }
      throw new Error(
        `No JSON object found in AI output. Raw (first 500 chars): ${rawJson.substring(0, 500)}`,
      );
    }
  }
}

return safeParseJson($input.first().json.output);

