const requestData = $input.all()[0].json
function filterProduct(data) {
  const verifiedProduct = data.products.filter(
    (product) =>
      product.existsInSystem ||
      (product.verifiedFromAttachment.attachmentName !== "N/A" &&
        product.verifiedFromAttachment.attachmentType),
  );
  return { ...data, products: verifiedProduct };
}

console.log(requestData);

const filteredData = filterProduct(requestData);

return filteredData
